%% Function fPhosShtLstV01.m %%%%%%%%%%% Function to get phosphor shot list, ver.1%% Kei Nakamura% Created on Friday, August 14th 2009.% Modified on Friday, August 20th 2010.%% function imgExst = fPhosShtLstV01(phsDir,nmbSht);% give a list of image exist logic % against phosphor camera% imgExst: logic of image exist% espcDir: directory to check image% nmbSht: number of shots from trex logfile% camNmb: camera number% ver.2: debug%%function [nmbImg,imgNmb,nameLst2] = fPhosShtLstV02(phsDir,nmbSht)   % function headername = ['/*_Phosphor_*.png'];nameLst = dir([phsDir,name]);         % information for Scan* file[nmbImg,dlt] = size(nameLst);   % number of imagesimgNmb(1) = 0;      % image numberkk = 1;     % index for actual shot takenfor jj=1:nmbImg    name = nameLst(jj).name;    if max(size(name))<26;        pp1 = find(name=='r');   % to get shot number from file name        pp2 = find(name=='.');        imgNmb(kk) = str2num(name(pp1+2:pp2-1));  % get shot number string        nameLst2(kk).name = name;        kk = kk +1;            endendnmbImg = kk-1;
